// src/SiparisIslemleri/SiparisOlustur.js
import React, { useEffect, useMemo, useRef, useState } from "react";
import {
    Download,
    Link as LinkIcon,
    ListChecks,
    IdCard,
    FileSpreadsheet,
    UploadCloud,
} from "lucide-react";
import * as XLSX from "xlsx";
import "./SiparisOlustur.css";
import supabase from "../supabaseClient";

/** --- Ayarlar --- **/
const DATA_TABLE = "Projeler"; // <-- VERİ BURADAN GELECEK

/** TABLODA KULLANILACAK GÜNCEL BAŞLIKLAR */
const HEADERS = [
    "Vkn",
    "Proje",
    "Sipariş Tarihi",
    "Yükleme Tarihi",
    "Teslim Tarihi",
    "Müşteri Sipariş No",
    "Müşteri Referans No",
    "İstenilen Araç Tipi",
    "Açıklama",
    "Yükleme Firması Adı",
    "Alıcı Firma Cari Adı",
    "Teslim Firma Adres Adı",
    "İrsaliye No",
    "İrsaliye Miktarı",
    "Ürün",
    "Kap Adet",
    "Ambalaj  Tipi",
    "Brüt KG",
    "M3",
    "Desi",
];

/** Export/Import için zorunlu başlıklar */
const REQUIRED_EXPORT_HEADERS = [
    "Sipariş Tarihi",
    "Müşteri Sipariş No",
    "İstenilen Araç Tipi",
    "Açıklama",
    "Yükleme Firma Adı",
    "Alıcı Firma Cari Adı",
    "Teslim Firma Adres Adı",
].map((h) => h.replace("Yükleme Firma Adı", "Yükleme Firması Adı"));

/** Supabase -> Tablo başlığı eşlemesi (overlay yapılacak alanlar) */
const FIELD_OVERLAY_MAP = {
    vkn: "Vkn",
    proje_id: "Proje",
    Musteri_Siparis_No: "Müşteri Sipariş No",
    Alici_Firma_Cari_Unvani: "Alıcı Firma Cari Adı",
    Urun: "Ürün",
    Kap_Adet: "Kap Adet",
    Ambalaj_Tipi: "Ambalaj  Tipi",
    Brut_KG: "Brüt KG",
    Yukleme_Firma_Adres_Adi: "Yükleme Firması Adı",
};
const SELECT_COLS = Object.keys(FIELD_OVERLAY_MAP).join(", ");

const emptyRow = () => HEADERS.reduce((acc, key) => ({ ...acc, [key]: "" }), {});
const sortTr = (a, b) => String(a).localeCompare(String(b), "tr", { sensitivity: "base" });
const normalize = (s) => String(s ?? "").replace(/\s+/g, " ").trim();

/* ===== Tarih + Araç Tipi yardımcıları ===== */
const excelSerialToDate = (val) => {
    const n = Number(val);
    if (!isFinite(n)) return null;
    const ms = n * 86400000;
    const d = new Date(Date.UTC(1899, 11, 30) + ms);
    return isNaN(d.getTime()) ? null : d;
};
const tryParseDate = (val) => {
    if (val === null || val === undefined || val === "") return null;
    const d1 = excelSerialToDate(val);
    if (d1) return d1;
    const d2 = new Date(val);
    return isNaN(d2.getTime()) ? null : d2;
};
const toShortTR = (date) => (date ? date.toLocaleDateString("tr-TR") : "");
const addDays = (date, days) => new Date(date.getTime() + days * 86400000);

const enrichDatesOnRow = (row) => {
    const raw = row["Sipariş Tarihi"];
    const d = tryParseDate(raw);
    if (!d) return row;
    return {
        ...row,
        ["Sipariş Tarihi"]: toShortTR(d),
        ["Yükleme Tarihi"]: toShortTR(d),
        ["Teslim Tarihi"]: toShortTR(addDays(d, 1)),
    };
};

const mapVehicleTypeToCode = (val) => {
    const raw = normalize(val);
    if (!raw) return raw;
    const s = raw.toLocaleLowerCase("tr");
    if (s === "tır" || s === "tir") return "1";
    if (s === "kırkayak" || s === "kirkayak") return "2";
    if (s === "kamyon") return "3";
    if (s === "kamyonet") return "5";
    return raw;
};
const enrichVehicleOnRow = (row) => ({
    ...row,
    ["İstenilen Araç Tipi"]: mapVehicleTypeToCode(row["İstenilen Araç Tipi"]),
});

const enrichRow = (row) => enrichVehicleOnRow(enrichDatesOnRow(row));

/* ====== Gelişmiş fuzzy eşleşme yardımcıları (adres + cari birlikte) ====== */

/** YENİ: güçlü normalizasyon + aliaslar + diakritik sadeleştirme **/
const NORM_ALIASES = [
    [/mah\.?|mh\.?/g, " mahalle "],
    [/cad\.?|cd\.?/g, " cadde "],
    [/sok\.?|sk\.?/g, " sokak "],
    [/bulv\.?|blv\.?/g, " bulvar "],
    [/org\.?\s*san\.?\s*böl\.?|osb/g, " organize sanayi bölgesi "],
    [/san\.?\s*sit\.?/g, " sanayi sitesi "],
    [/tic\.?/g, " ticaret "],
    [/san\.?/g, " sanayi "],
    [/ltd\.?/g, " limited "],
    [/(ş|s)ti|şti|sti/g, " şirketi "],
    [/a\.?ş\.?/g, " anonim "],
];

const stripDiacriticsTR = (s) =>
    s
        .replace(/ğ/g, "g").replace(/ü/g, "u").replace(/ş/g, "s")
        .replace(/ı/g, "i").replace(/İ/g, "i")
        .replace(/ö/g, "o").replace(/ç/g, "c")
        .replace(/Ğ/g, "g").replace(/Ü/g, "u").replace(/Ş/g, "s")
        .replace(/Ö/g, "o").replace(/Ç/g, "c");

const normalizeText = (input) => {
    let s = String(input ?? "")
        .normalize("NFKD")
        .toLocaleLowerCase("tr")
        .replace(/[\(\)\[\]\{\}_:;!@#%^*+=\/\\|<>?"'`~]/g, " ")
        .replace(/[.,-]/g, " ")
        .replace(/\s+/g, " ")
        .trim();
    for (const [rx, rep] of NORM_ALIASES) s = s.replace(rx, rep);
    return s.replace(/\s+/g, " ").trim();
};

// ESKİ cleanAddr'ın yerine bu kullanılacak:
const cleanAddr = (s) => normalizeText(s);

// diakritiksiz ikincil temsil (skorlama yedeği için)
const normalizedPairs = (s) => {
    const norm = normalizeText(s);
    const ascii = stripDiacriticsTR(norm);
    return { norm, ascii };
};

const bigrams = (str) => {
    const s = str.replace(/\s+/g, "");
    const arr = [];
    for (let i = 0; i < Math.max(0, s.length - 1); i++) arr.push(s.slice(i, i + 2));
    return arr;
};
const diceCoefficient = (a, b) => {
    if (!a || !b) return 0;
    if (a === b) return 1;
    const A = bigrams(a), B = bigrams(b);
    if (!A.length || !B.length) return 0;
    const map = new Map();
    for (const g of A) map.set(g, (map.get(g) ?? 0) + 1);
    let inter = 0;
    for (const g of B) {
        const c = map.get(g) ?? 0;
        if (c > 0) { inter++; map.set(g, c - 1); }
    }
    return (2 * inter) / (A.length + B.length);
};

// Şirket/Sektör + adres ekleri (stopword) temizliği (genişletildi)
const STOPWORDS = new Set([
    "san", "tic", "ltd", "sti", "ştı", "şti", "aş", "a.ş", "a.ş.",
    "ve", "gida", "gıda", "ins", "inş", "insaat", "inşaat", "sanayi",
    "ticaret", "anonim", "limited", "sirketi", "şirketi", "co", "ltd.",
    "unlu", "mam", "mamulleri", "ekmek", "firin", "fırın",
    // adres genel
    "mah", "mahalle", "cad", "cadde", "sok", "sokak", "bulvar", "blv",
    "no", "daire", "daireno", "blok", "site", "ap", "apartman", "kat",
    "mevkii", "organize", "sanayi", "bölgesi", "osb", "sanayi", "sitesi"
]);
const tokenize = (s) => cleanAddr(s)
    .split(" ")
    .filter(Boolean)
    .map(t => t.replace(/\.+$/g, ""))
    .filter(t => t && !STOPWORDS.has(t));

const buildRowAddrOnly = (row) => cleanAddr(row["Teslim Firma Adres Adı"] || "");
const buildRowCariOnly = (row) => cleanAddr(row["Alıcı Firma Cari Adı"] || "");

// Aday metni: adres + (varsa) cari adı/unvanı + cari_hesap_id
const buildCandidateText = (cand) => {
    const parts = [
        cand.adres_adi,
        cand.cari_adi,
        cand.cari_unvani,
        cand.cari_adi2,
        cand.cari_hesap_id,
    ].filter(Boolean);
    return cleanAddr(parts.join(" "));
};

/** YENİ: Jaro-Winkler (kısa isimlerde iyi çalışır) */
const jaroWinkler = (s1, s2) => {
    if (!s1 || !s2) return 0;
    const mDist = Math.floor(Math.max(s1.length, s2.length) / 2) - 1;
    const s1M = new Array(s1.length).fill(false);
    const s2M = new Array(s2.length).fill(false);
    let matches = 0, trans = 0;

    for (let i = 0; i < s1.length; i++) {
        const start = Math.max(0, i - mDist);
        const end = Math.min(i + mDist + 1, s2.length);
        for (let j = start; j < end; j++) {
            if (s2M[j]) continue;
            if (s1[i] !== s2[j]) continue;
            s1M[i] = true; s2M[j] = true; matches++; break;
        }
    }
    if (!matches) return 0;

    let k = 0;
    for (let i = 0; i < s1.length; i++) {
        if (!s1M[i]) continue;
        while (!s2M[k]) k++;
        if (s1[i] !== s2[k]) trans++;
        k++;
    }
    trans /= 2;

    const jaro = (matches / s1.length + matches / s2.length + (matches - trans) / matches) / 3;
    let prefix = 0;
    for (let i = 0; i < Math.min(4, s1.length, s2.length); i++) {
        if (s1[i] === s2[i]) prefix++; else break;
    }
    return jaro + prefix * 0.1 * (1 - jaro);
};

const tokenSet = (s) => new Set(tokenize(s));
const tokenCoverage = (q, c) => {
    const qT = tokenize(q), cT = tokenSet(c);
    if (!qT.length) return 0;
    let m = 0; for (const t of qT) if (cT.has(t)) m++;
    return m / qT.length;
};

const scorePair = (q, c) => {
    const { norm: qn, ascii: qa } = normalizedPairs(q);
    const { norm: cn, ascii: ca } = normalizedPairs(c);

    const covN = tokenCoverage(qn, cn);
    const covA = tokenCoverage(qa, ca);

    const diceN = diceCoefficient(qn, cn);
    const diceA = diceCoefficient(qa, ca);

    const jwN = jaroWinkler(qn, cn);
    const jwA = jaroWinkler(qa, ca);

    const sNorm = 0.6 * covN + 0.3 * diceN + 0.1 * jwN;
    const sAscii = 0.6 * covA + 0.3 * diceA + 0.1 * jwA;

    return Math.max(sNorm, sAscii);
};

const containsAllTokens = (q, c) => {
    const qT = tokenize(q), cT = tokenSet(c);
    return qT.length > 0 && qT.every(t => cT.has(t));
};

/** YENİ: Alan-bilinçli ana skorlayıcı (adres-only, cari-only ve karışık yazımlar için) */
const fieldAwareScore = (row, cand) => {
    const qAddr = cleanAddr(row["Teslim Firma Adres Adı"] || "");
    const qCari = cleanAddr(row["Alıcı Firma Cari Adı"] || "");
    const qAll = cleanAddr(`${qAddr} ${qCari}`) || qAddr || qCari;

    const cAddr = cleanAddr(cand.adres_adi || "");
    const cCari = cleanAddr(`${cand.cari_adi || ""} ${cand.cari_unvani || ""} ${cand.cari_hesap_id || ""}`);
    const cAll = `${cAddr} ${cCari}`.trim();

    // Sert içerme kısayolu (hızlı yüksek skor)
    if (containsAllTokens(qCari, cAll) || containsAllTokens(qAddr, cAll)) return 0.99;

    // Kombinasyonlar
    const sCombined = scorePair(qAll, cAll);
    const sAddrOnly = scorePair(qAddr, cAll);
    const sCariOnly = scorePair(qCari, cAll);

    // Alan ağırlıkları + çapraz bonus
    const wCari = 0.6, wAddr = 0.4;
    const base = Math.max(sCombined, wAddr * sAddrOnly + wCari * sCariOnly);

    const qCariTokens = tokenSet(qCari);
    const cAddrTokens = tokenSet(cAddr);
    let inter = 0;
    qCariTokens.forEach(t => { if (cAddrTokens.has(t)) inter++; });
    const crossBonus = Math.min(0.08, inter * 0.02);

    const shortQBonus = (qCari.split(" ").length <= 2 || qAddr.split(" ").length <= 2) ? 0.03 : 0;

    return Math.min(1, base + crossBonus + shortQBonus);
};

// En iyi eşleşmeyi hem cari hem adres kombinasyonlarını deneyerek bul — YENİ sürüm
const bestDualFieldScore = (row, cand) => fieldAwareScore(row, cand);

/** YENİ: Adaptif eşik (kısa metinlerde daha sıkı, uzunlarda daha esnek) */
const computeThreshold = (row) => {
    const qAddr = cleanAddr(row["Teslim Firma Adres Adı"] || "");
    const qCari = cleanAddr(row["Alıcı Firma Cari Adı"] || "");
    const len = (qAddr + " " + qCari).split(" ").filter(Boolean).length;
    if (len <= 3) return 0.40;   // çok kısa metin -> eşik yükselt
    if (len >= 12) return 0.30;  // uzun metin -> biraz gevşet
    return 0.33;
};

export default function SiparisOlustur() {
    const [projeAdi, setProjeAdi] = useState("");
    const [rows, setRows] = useState([]);
    const [dragActive, setDragActive] = useState(false);
    const [error, setError] = useState("");
    const [lastFile, setLastFile] = useState(null);
    const fileInputRef = useRef(null);

    const [projects, setProjects] = useState([]);
    const [projectsLoading, setProjectsLoading] = useState(false);
    const [projectsError, setProjectsError] = useState("");

    const [overlayLoading, setOverlayLoading] = useState(false);

    const columns = useMemo(() => HEADERS, []);

    const [matchModalOpen, setMatchModalOpen] = useState(false);
    const [matchPreview, setMatchPreview] = useState({
        total: 0,
        matchedCount: 0,
        unmatchedCount: 0,
        samples: [],
        unmatchedSamples: [],
    });
    const [matchResults, setMatchResults] = useState([]);

    useEffect(() => {
        const fetchProjects = async () => {
            setProjectsLoading(true);
            setProjectsError("");
            try {
                const { data, error } = await supabase
                    .from("Projeler")
                    .select("id, Proje_Adi");
                if (error) throw error;

                const list = (Array.isArray(data) ? data : [])
                    .map((x) => ({ id: x?.id, name: (x?.Proje_Adi ?? "").trim() }))
                    .filter((x) => x.id && x.name.length > 0)
                    .sort((a, b) => sortTr(a.name, b.name));

                setProjects(list);
            } catch (e) {
                setProjectsError(e.message || "Projeler alınırken hata oluştu.");
                setProjects([]);
            } finally {
                setProjectsLoading(false);
            }
        };

        fetchProjects();
    }, []);

    const isExcelFile = (file) =>
        /\.(xlsx|xlsm|xls)$/i.test(file.name) ||
        [
            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            "application/vnd.ms-excel",
        ].includes(file.type);

    const parseExcel = async (file) => {
        setError("");
        try {
            if (!projeAdi) throw new Error("Excel yüklemeden önce lütfen bir proje seçin.");
            if (!isExcelFile(file)) throw new Error("Lütfen .xlsx / .xls dosyası yükleyin.");

            const buf = await file.arrayBuffer();
            const wb = XLSX.read(buf, { type: "array" });
            const ws = wb.Sheets[wb.SheetNames[0]];
            const aoa = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" });
            if (!aoa || aoa.length === 0) throw new Error("Boş sayfa görünüyor.");

            const [rawHeaders, ...body] = aoa;

            const headerIndexMap = {};
            HEADERS.forEach((h) => {
                const idx = rawHeaders.findIndex((x) => normalize(x) === normalize(h));
                headerIndexMap[h] = idx;
            });

            const missing = REQUIRED_EXPORT_HEADERS.filter((h) => headerIndexMap[h] === -1);
            if (missing.length) throw new Error(`Eksik başlık: ${missing.join(", ")}. Lütfen şablonu kullanın.`);

            const parsedRows = body
                .filter((row) => row.some((cell) => normalize(cell) !== ""))
                .map((row) => {
                    const obj = {};
                    HEADERS.forEach((h) => {
                        const idx = headerIndexMap[h];
                        obj[h] = idx >= 0 ? normalize(row[idx]) : "";
                    });
                    return enrichRow(obj);
                })
                .map((r) => ({ ...r, Proje: projeAdi || "" }));

            try {
                const incoming = await fetchProjectRows(projeAdi);
                const merged = applyOverlay(parsedRows, incoming);
                setRows(merged);
            } catch (er) {
                setRows(parsedRows);
                setError(er.message || "Proje verileri alınamadı (Excel yüklendi).");
            }

            setLastFile(file);
        } catch (e) {
            setRows([]);
            setError(e.message || "Excel okunamadı.");
        }
    };

    const onDrop = (e) => {
        e.preventDefault();
        setDragActive(false);
        const f = e.dataTransfer.files?.[0];
        if (f) parseExcel(f);
    };
    const onDragOver = (e) => { e.preventDefault(); setDragActive(true); };
    const onDragLeave = () => setDragActive(false);
    const pickFile = () => fileInputRef.current?.click();
    const onFileChange = (e) => { const f = e.target.files?.[0]; if (f) parseExcel(f); e.target.value = ""; };

    const handleTemplateDownload = () => {
        const cols = REQUIRED_EXPORT_HEADERS;
        const wsData = [cols, ...[emptyRow()].map((r) => cols.map((c) => r[c] ?? ""))];
        const ws = XLSX.utils.aoa_to_sheet(wsData);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Sablon");
        XLSX.writeFile(wb, `Siparis_Sablon_${new Date().toISOString().slice(0, 10)}.xlsx`);
    };

    const handleExportExcel = () => {
        if (!projeAdi) {
            setError("Dışa aktarmadan önce lütfen bir proje seçin.");
            return;
        }
        if (!rows.length) {
            setError("Dışa aktarılacak veri bulunamadı.");
            return;
        }

        const cols = ["#", ...columns];
        const aoa = [
            cols,
            ...rows.map((r, i) => [
                i + 1,
                ...columns.map((c) => r[c] ?? "")
            ]),
        ];

        const ws = XLSX.utils.aoa_to_sheet(aoa);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Tablo");

        const iso = new Date().toISOString().slice(0, 10);
        XLSX.writeFile(wb, `Siparisler_${projeAdi || "Proje"}_${iso}.xlsx`);
    };

    const fetchProjectRows = async (projectName) => {
        const { data, error } = await supabase
            .from(DATA_TABLE)
            .select(`${SELECT_COLS}, Proje_Adi`)
            .eq("Proje_Adi", projectName);

        if (error) throw error;
        return Array.isArray(data) ? data : [];
    };

    const applyOverlay = (prevRows, incoming) => {
        const outLen = Math.max(prevRows.length, incoming.length || 0);
        const hasAny = Array.isArray(incoming) && incoming.length > 0;

        const out = Array.from({ length: outLen }).map((_, i) => {
            const base = prevRows[i] ? { ...prevRows[i] } : emptyRow();
            const rec = hasAny ? (incoming[i] ?? incoming[incoming.length - 1]) : null;
            if (rec) {
                Object.entries(FIELD_OVERLAY_MAP).forEach(([src, dest]) => {
                    if (src === "proje_id") {
                        base[dest] = String(rec.proje_id ?? "");
                    } else {
                        base[dest] = normalize(rec[src] ?? base[dest]);
                    }
                });
            }
            return enrichRow(base);
        });

        return out;
    };

    const overlayProjectData = (incoming) => {
        setRows((prev) => applyOverlay(prev, incoming));
    };

    const handleEslesmeYap = async () => {
        try {
            if (!projeAdi) {
                setError("Eşleşme yapmadan önce lütfen bir proje seçin.");
                return;
            }
            setError("");
            setOverlayLoading(true);

            try {
                const incoming = await fetchProjectRows(projeAdi);
                if (incoming && incoming.length) {
                    const merged = applyOverlay(rows, incoming);
                    setRows(merged);
                }
            } catch (_) { }

            // Teslim_Noktalari: geniş seçim dene, olmazsa güvenli sete düş
            let data, error;
            ({ data, error } = await supabase
                .from("Teslim_Noktalari")
                .select("adres_id, adres_adi, cari_hesap_id, cari_adi, cari_unvani"));
            if (error) {
                ({ data, error } = await supabase
                    .from("Teslim_Noktalari")
                    .select("adres_id, adres_adi, cari_hesap_id"));
                if (error) throw error;
            }

            const adresler = (Array.isArray(data) ? data : []).map((x) => ({
                adres_id: x?.adres_id ?? "",
                adres_adi: x?.adres_adi ?? "",
                cari_hesap_id: x?.cari_hesap_id ?? "",
                cari_adi: x?.cari_adi ?? "",
                cari_unvani: x?.cari_unvani ?? "",
            }));

            const currentRows = rows;
            const results = currentRows.map((row, idx) => {
                const qText = cleanAddr(`${row["Teslim Firma Adres Adı"] || ""} ${row["Alıcı Firma Cari Adı"] || ""}`);
                if (!qText) return { rowIndex: idx, ok: false, before: qText, score: 0 };

                let best = null, bestScore = 0;
                for (const a of adresler) {
                    const s = bestDualFieldScore(row, a);
                    if (s > bestScore) { bestScore = s; best = a; }
                }

                const TH = computeThreshold(row);

                if (best && bestScore >= TH) {
                    return {
                        rowIndex: idx,
                        ok: true,
                        score: bestScore,
                        before: qText,
                        matchedAdresAdi: best.adres_adi,
                        matchedAdresId: best.adres_id,
                        matchedCariId: best.cari_hesap_id,
                        bestTryAdresAdi: best.adres_adi,
                        bestTryAdresId: best.adres_id,
                        bestTryCariId: best.cari_hesap_id,
                    };
                }
                return {
                    rowIndex: idx,
                    ok: false,
                    before: qText,
                    score: bestScore,
                    bestTryAdresAdi: best?.adres_adi ?? "",
                    bestTryAdresId: best?.adres_id ?? "",
                    bestTryCariId: best?.cari_hesap_id ?? "",
                };
            });

            const matched = results.filter(r => r.ok);
            const unmatched = results.filter(r => !r.ok).slice(0, 8);
            setMatchResults(results);
            setMatchPreview({
                total: currentRows.length,
                matchedCount: matched.length,
                unmatchedCount: currentRows.length - matched.length,
                samples: matched.slice(0, 8).map(r => ({
                    rowIndex: r.rowIndex,
                    before: r.before,
                    matchedAdresAdi: r.matchedAdresAdi,
                    matchedAdresId: r.matchedAdresId,
                    matchedCariId: r.matchedCariId,
                    score: r.score,
                })),
                unmatchedSamples: unmatched.map(r => ({
                    rowIndex: r.rowIndex,
                    before: r.before,
                    bestTryAdresAdi: r.bestTryAdresAdi,
                    bestTryAdresId: r.bestTryAdresId,
                    bestTryCariId: r.bestTryCariId,
                    score: r.score,
                })),
            });
            setMatchModalOpen(true);
        } catch (e) {
            setError(e.message || "Eşleşme sırasında hata oluştu.");
        } finally {
            setOverlayLoading(false);
        }
    };

    const confirmApplyMatches = () => {
        setRows(prev => {
            const byIndex = new Map();
            for (const r of matchResults) if (r.ok) byIndex.set(r.rowIndex, r);
            return prev.map((row, i) => {
                const m = byIndex.get(i);
                if (!m) return row;
                const next = { ...row };
                next["Teslim Firma Adres Adı"] = String(m.matchedAdresId ?? "");
                next["Alıcı Firma Cari Adı"] = String(m.matchedCariId ?? "");
                return next;
            });
        });
        setMatchModalOpen(false);
    };

    const cancelMatches = () => setMatchModalOpen(false);

    const handleEslesmeIdGetir = () => {
        if (!projeAdi) {
            setError("Eşleşme ID’lerini getirmeden önce lütfen bir proje seçin.");
            return;
        }
        const fakeId = Math.random().toString(36).slice(2, 10).toUpperCase();
        alert(`Eşleşme ID'si: ${fakeId}`);
    };

    return (
        <div className="so-page">
            <div className="so-header">
                <div>
                    <h1 className="so-title">Sipariş Oluştur</h1>
                    <div className="so-subtitle">SiparisOlustur.js</div>
                </div>
            </div>

            <div className="so-grid so-grid--two">
                <div className="so-card so-equal">
                    <label className="so-label">
                        Proje Adı <span style={{ color: "#e11d48" }}>*</span>
                    </label>
                    <select
                        className="so-input"
                        value={projeAdi}
                        onChange={(e) => setProjeAdi(e.target.value)}
                        disabled={projectsLoading}
                    >
                        <option value="">Seçiniz</option>
                        {projectsLoading && <option>Yükleniyor...</option>}
                        {!projectsLoading && projectsError && (
                            <option disabled>Hata: {projectsError}</option>
                        )}
                        {!projectsLoading && !projectsError &&
                            projects.map((p) => (
                                <option key={p.id} value={p.name}>{p.name}</option>
                            ))}
                    </select>
                    <p className="so-help">
                        Proje seçmek zorunludur. Excel yükleyebilir veya “Eşleşme Yap” ile
                        projedeki alanları mevcut satırlara yerleştirebilirsiniz.
                    </p>
                </div>

                <div className="so-card so-equal">
                    <div className="so-actions">
                        <button className="so-btn so-btn-primary" onClick={handleTemplateDownload}>
                            <Download size={18} /> Şablonu İndir
                        </button>
                        <button className="so-btn" onClick={handleEslesmeYap} disabled={!projeAdi || overlayLoading}>
                            <LinkIcon size={18} /> {overlayLoading ? "Eşleştiriliyor..." : "Eşleşme Yap"}
                        </button>
                        <button className="so-btn" onClick={handleEslesmeIdGetir} disabled={!projeAdi}>
                            <IdCard size={18} /> Eşleşme ID’lerini Getir
                        </button>
                        <button className="so-btn" onClick={handleExportExcel} disabled={!rows.length || !projeAdi}>
                            <FileSpreadsheet size={18} /> Dışarı Excel Aktarma
                        </button>
                    </div>
                </div>
            </div>

            <div className="so-table-card">
                <div className="so-table-header">
                    <ListChecks size={18} /> <span>Şablon</span>
                    <span className="so-table-sub">
                        (İçerik Excel ile yüklenir; proje verileri tüm satırlara uygulanır. Sipariş = kısa tarih, Yükleme = Sipariş, Teslim = +1 gün. Araç tipi: TIR→1, KIRKAYAK→2, KAMYON→3, KAMYONET→5)
                    </span>
                </div>

                <div className="so-table-wrap">
                    <table className="so-table">
                        <thead>
                            <tr>
                                <th className="so-index">#</th>
                                {columns.map((c) => (
                                    <th key={c}>{c}</th>
                                ))}
                            </tr>
                        </thead>
                        <tbody>
                            {rows.length === 0 ? (
                                <tr className="so-drop-row">
                                    <td className="so-index" colSpan={columns.length + 1}>
                                        <div
                                            className={`so-drop-in-table ${dragActive ? "active" : ""}`}
                                            onDrop={onDrop}
                                            onDragOver={onDragOver}
                                            onDragLeave={onDragLeave}
                                            onDragEnd={onDragLeave}
                                            onDragExit={onDragLeave}
                                            onClick={pickFile}
                                            role="button"
                                            aria-label="Excel sürükleyip bırak veya tıklayıp seç"
                                            tabIndex={0}
                                        >
                                            <UploadCloud size={30} />
                                            <div className="so-drop-title">Excel’i buraya sürükleyip bırakın</div>
                                            <div className="so-drop-sub">ya da <b>tıklayın</b> (.xlsx / .xls)</div>
                                            <input
                                                ref={fileInputRef}
                                                type="file"
                                                accept=".xlsx,.xls,.xlsm"
                                                onChange={onFileChange}
                                                hidden
                                                disabled={!projeAdi}
                                            />
                                        </div>
                                    </td>
                                </tr>
                            ) : (
                                rows.map((row, rowIdx) => (
                                    <tr key={rowIdx}>
                                        <td className="so-index">{rowIdx + 1}</td>
                                        {columns.map((col) => (
                                            <td key={`${rowIdx}-${col}`}>
                                                <div className="so-cell-text">{row[col]}</div>
                                            </td>
                                        ))}
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>

                <div className="so-footnote">
                    İpucu: “Şablonu İndir” ile başlıkları hazır Excel elde edip, doldurduktan sonra buraya yükleyebilirsiniz.
                </div>

                {error && <p className="so-error">{error}</p>}
                {lastFile && (
                    <p className="so-help">Yüklü: <b>{lastFile.name}</b></p>
                )}
            </div>

            {matchModalOpen && (
                <div className="so-modal-backdrop" role="dialog" aria-modal="true">
                    <div className="so-modal">
                        <div className="so-modal__body">
                            <h3 className="so-modal__title">Adres + Cari Eşleşme Özeti</h3>
                            <p className="so-modal__kpi">
                                Toplam satır: <b>{matchPreview.total}</b>
                                {" — "}Eşleşen: <b className="good">{matchPreview.matchedCount}</b>
                                {" — "}Eşleşmeyen: <b className="bad">{matchPreview.unmatchedCount}</b>
                            </p>

                            {matchPreview.samples?.length > 0 && (
                                <>
                                    <div style={{ fontWeight: 600, marginBottom: 6 }}>Örnek eşleşmeler:</div>
                                    <ul className="so-modal__list">
                                        {matchPreview.samples.map((s) => (
                                            <li key={s.rowIndex}>
                                                <code>{s.before}</code> → <code>{s.matchedAdresAdi}</code>
                                                {" "}(adres_id: <b>{s.matchedAdresId}</b>, cari_hesap_id: <b>{s.matchedCariId}</b>)
                                            </li>
                                        ))}
                                    </ul>
                                </>
                            )}

                            {matchPreview.unmatchedSamples?.length > 0 && (
                                <>
                                    <div style={{ fontWeight: 600, marginTop: 12, marginBottom: 6 }}>Eşleşmeyen örnekler (en yakın aday ve skor):</div>
                                    <ul className="so-modal__list">
                                        {matchPreview.unmatchedSamples.map((s) => (
                                            <li key={`un-${s.rowIndex}`}>
                                                <code>{s.before || "—"}</code>
                                                {"  →  "}
                                                {s.bestTryAdresAdi ? (
                                                    <>
                                                        en yakın: <code>{s.bestTryAdresAdi}</code>
                                                        {" "}(adres_id: <b>{s.bestTryAdresId || "—"}</b>, cari_hesap_id: <b>{s.bestTryCariId || "—"}</b>, skor: {s.score.toFixed(2)})
                                                    </>
                                                ) : "uygun aday bulunamadı"}
                                            </li>
                                        ))}
                                    </ul>
                                    <div className="so-modal__hint">İpucu: Benzerlik eşiği satırın metin uzunluğuna göre değişir (≈0.30–0.40).</div>
                                </>
                            )}
                        </div>

                        <div className="so-modal__actions">
                            <button className="so-btn" onClick={() => setMatchModalOpen(false)}>Vazgeç</button>
                            <button className="so-btn so-btn-primary" onClick={confirmApplyMatches}>Onayla ve Uygula</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}
